import crypto from "node:crypto";
import { Router } from "express";
import { verifyCredential } from "../services/credentialVerifier.js";
import { evaluateConstraints } from "../services/constraintEvaluator.js";
import { applyLocalPolicyMerge } from "../services/localPolicyMerge.js";
import { verifyDelegationChain } from "../services/delegationVerifier.js";
import { createAuditRecord } from "../services/auditLogger.js";
import { evaluateStatefulConstraints } from "../services/statefulAuthorizer.js";
import { enrichRequestContext } from "../services/contextEnricher.js";
import { getPool } from "../db/pool.js";
import { validateRoleCoverage, combineSubDecisions } from "../services/workflowEvaluator.js";

const router = Router();

// ── Evaluation auth gate ─────────────────────────────────────────────
// Optional bearer gate for the evaluation endpoints. When
// ENGINE_EVALUATE_AUTH_TOKEN is set, callers (e.g. A2A receivers) MUST present
// a matching token, so the evaluator cannot be reached directly around the
// receiver. When unset, the endpoint is open for local/compose use. Pairs with
// the A2A receiver's A2A_ENGINE_AUTH_TOKEN. Comparison is timing-safe.
export function requireEvaluateAuth(req, res, next) {
  const expected = process.env.ENGINE_EVALUATE_AUTH_TOKEN || "";
  if (!expected) return next();
  const authHeader = req.headers?.authorization || "";
  if (!authHeader.startsWith("Bearer ")) {
    return res.status(401).json({ error: "unauthorized", message: "Missing or malformed Authorization header" });
  }
  const supplied = Buffer.from(authHeader.slice(7));
  const expectedBuf = Buffer.from(expected);
  if (supplied.length !== expectedBuf.length || !crypto.timingSafeEqual(supplied, expectedBuf)) {
    return res.status(401).json({ error: "unauthorized", message: "Invalid evaluate token" });
  }
  return next();
}

router.use(requireEvaluateAuth);

function evaluatorId() {
  return process.env.PORTAUTH_EVALUATOR_ID
    || process.env.EVALUATOR_ID
    || process.env.PORTAUTH_ENGINE_AUDIENCE
    || process.env.ENGINE_AUDIENCE
    || null;
}

function requestIdempotencyKey(req, requestContext) {
  return req.body?.idempotencyKey
    || req.get("Idempotency-Key")
    || requestContext?.idempotencyKey
    || null;
}

// ── POST /evaluate ──────────────────────────────────────────────────
// Evaluate a single credential against a request context
router.post("/", async (req, res) => {
  const { credential, presenterId } = req.body || {};
  let requestContext = req.body?.requestContext;

  // Input validation
  if (!credential) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: credential" });
  }
  if (!requestContext || !requestContext.action || !requestContext.resource) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: requestContext with action and resource" });
  }
  if (!presenterId) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: presenterId" });
  }

  try {
    // ── Step 1: Verify credential ─────────────────────────────────
    const introspectionUrl = req.body.introspectionUrl || null;
    const verification = await verifyCredential(credential, presenterId, {
      introspectionUrl,
      evaluatorId: evaluatorId(),
      requestContext,
      proofOfPossession: req.body.proofOfPossession,
    });

    if (!verification.verified) {
      const auditRecordId = await createAuditRecord({
        credentialId: null,
        agentId: null,
        issuerId: null,
        action: requestContext.action,
        resource: requestContext.resource,
        requestContext,
        verificationResult: { valid: false, error: verification.error },
        decision: "deny",
        errorCode: verification.errorCode,
        httpStatus: 422,
      });

      return res.status(422).json({
        decision: "deny",
        error: verification.errorCode,
        message: verification.error,
        auditRecordId,
      });
    }

    const payload = verification.payload;

    // Plan 4: enrich request context with credential-derived and request-envelope
    // facts so MVV semantic identifiers (core.issuer_id, core.request_id, etc.)
    // can resolve uniformly via the semantic resolver.
    requestContext = enrichRequestContext({ requestContext, payload, presenterId, req });

    // ── Step 2: Permission match ──────────────────────────────────
    const requestedAction = requestContext.action;
    const permissionMatched = payload.permissions.includes(requestedAction);

    if (!permissionMatched) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        verificationResult: { valid: true, checks: verification.checks },
        permissionMatch: { matched: false, requested: requestedAction, granted: payload.permissions },
        decision: "deny",
        errorCode: "permission_denied",
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: "permission_denied",
        message: `Requested action '${requestedAction}' not in granted permissions: [${payload.permissions.join(", ")}]`,
        auditRecordId,
        verification: { valid: true, checks: verification.checks },
        permissionMatch: { matched: false, requested: requestedAction, granted: payload.permissions },
      });
    }

    // ── Step 3: Evaluate credential constraints ───────────────────
    const constraintEval = await evaluateConstraints(payload.constraints, requestContext);

    if (!constraintEval.pass) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        verificationResult: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true, requested: requestedAction, granted: payload.permissions },
        constraintResults: constraintEval.results,
        decision: "deny",
        errorCode: constraintEval.error,
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: constraintEval.error,
        message: constraintEval.results.find(r => !r.pass)?.detail,
        auditRecordId,
        verification: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true },
        constraintResults: constraintEval.results,
      });
    }

    // ── Step 4: Local policy merge ────────────────────────────────
    const localMerge = await applyLocalPolicyMerge(payload, requestContext);

    if (localMerge.denied) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        verificationResult: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true },
        constraintResults: constraintEval.results,
        localPolicyApplied: true,
        localPolicyDetail: localMerge.localPolicyDetail,
        decision: "deny",
        errorCode: "local_policy_denied",
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: "local_policy_denied",
        message: "Request denied by receiver local policy",
        auditRecordId,
        verification: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true },
        constraintResults: constraintEval.results,
        localPolicyApplied: true,
        localPolicyDetail: localMerge.localPolicyDetail,
      });
    }

    // ── Step 5: Stateful authorization profiles ──────────────────
    const statefulEval = await evaluateStatefulConstraints(payload.constraints, requestContext, payload, {
      idempotencyKey: requestIdempotencyKey(req, requestContext),
    });

    if (!statefulEval.pass) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        verificationResult: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true },
        constraintResults: [...constraintEval.results, ...statefulEval.results],
        localPolicyApplied: localMerge.localPolicyApplied,
        localPolicyDetail: localMerge.localPolicyDetail,
        decision: "deny",
        errorCode: statefulEval.error,
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: statefulEval.error,
        message: statefulEval.results.find(r => !r.pass)?.detail,
        auditRecordId,
        verification: { valid: true, checks: verification.checks },
        permissionMatch: { matched: true },
        constraintResults: constraintEval.results,
        statefulResults: statefulEval.results,
        localPolicyApplied: localMerge.localPolicyApplied,
      });
    }

    // ── Step 6: All checks pass → Allow ───────────────────────────
    const auditRecordId = await createAuditRecord({
      credentialId: payload.credentialId,
      agentId: payload.agentId,
      issuerId: payload.issuerId,
      trustTier: payload.trustTier,
      action: requestedAction,
      resource: requestContext.resource,
      requestContext,
      verificationResult: { valid: true, checks: verification.checks },
      permissionMatch: { matched: true, requested: requestedAction, granted: payload.permissions },
      constraintResults: [...constraintEval.results, ...statefulEval.results],
      localPolicyApplied: localMerge.localPolicyApplied,
      localPolicyDetail: localMerge.localPolicyDetail,
      decision: "allow",
      httpStatus: 200,
    });

    return res.status(200).json({
      decision: "allow",
      auditRecordId,
      verification: { valid: true, checks: verification.checks },
      permissionMatch: { matched: true, requested: requestedAction, granted: payload.permissions },
      constraintResults: constraintEval.results,
      statefulResults: statefulEval.results,
      localPolicyApplied: localMerge.localPolicyApplied,
    });
  } catch (err) {
    console.error("Evaluation error:", err);
    if (err && typeof err.message === "string" && err.message.startsWith("audit_signing_failed")) {
      return res.status(500).json({ error: "audit_signing_failed", message: err.message });
    }
    return res.status(500).json({ error: "internal_error", message: "Evaluation failed unexpectedly" });
  }
});

// ── POST /evaluate/batch ──────────────────────────────────────────────
// Evaluate a delegation chain against a request context
router.post("/batch", async (req, res) => {
  const { credentials, presenterId } = req.body || {};
  let requestContext = req.body?.requestContext;

  if (!credentials || !Array.isArray(credentials) || credentials.length === 0) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: credentials (array)" });
  }
  if (!requestContext || !requestContext.action || !requestContext.resource) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: requestContext with action and resource" });
  }
  if (!presenterId) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: presenterId" });
  }

  try {
    const introspectionUrl = req.body.introspectionUrl || null;
    const chainResult = await verifyDelegationChain(credentials, presenterId, {
      introspectionUrl,
      evaluatorId: evaluatorId(),
      requestContext,
      proofOfPossession: req.body.proofOfPossession,
    });

    if (!chainResult.verified) {
      const auditRecordId = await createAuditRecord({
        action: requestContext.action,
        resource: requestContext.resource,
        requestContext,
        delegationDepth: chainResult.chainDepth || 0,
        verificationResult: { valid: false, error: chainResult.error },
        decision: "deny",
        errorCode: chainResult.errorCode,
        httpStatus: chainResult.errorCode === "delegation_widened" ? 200 : 422,
      });

      const httpStatus = chainResult.errorCode === "delegation_widened" ? 200 : 422;
      return res.status(httpStatus).json({
        decision: "deny",
        error: chainResult.errorCode,
        message: chainResult.error,
        auditRecordId,
        chainDepth: chainResult.chainDepth,
      });
    }

    // Chain verified, now evaluate the leaf credential's constraints
    const payload = chainResult.payload;
    const requestedAction = requestContext.action;

    // Plan 4: enrich request context with credential-derived and request-envelope
    // facts so MVV semantic identifiers can resolve via the semantic resolver.
    requestContext = enrichRequestContext({ requestContext, payload, presenterId, req });

    // Permission match
    if (!payload.permissions.includes(requestedAction)) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        delegationDepth: chainResult.chainDepth,
        permissionMatch: { matched: false, requested: requestedAction, granted: payload.permissions },
        decision: "deny",
        errorCode: "permission_denied",
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: "permission_denied",
        message: `Requested action '${requestedAction}' not in leaf credential permissions`,
        auditRecordId,
        chainDepth: chainResult.chainDepth,
      });
    }

    // Constraint evaluation
    const constraintEval = await evaluateConstraints(payload.constraints, requestContext);

    if (!constraintEval.pass) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        delegationDepth: chainResult.chainDepth,
        constraintResults: constraintEval.results,
        decision: "deny",
        errorCode: constraintEval.error,
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: constraintEval.error,
        auditRecordId,
        chainDepth: chainResult.chainDepth,
        constraintResults: constraintEval.results,
      });
    }

    // Local policy merge
    const localMerge = await applyLocalPolicyMerge(payload, requestContext);
    if (localMerge.denied) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        delegationDepth: chainResult.chainDepth,
        constraintResults: constraintEval.results,
        localPolicyApplied: true,
        localPolicyDetail: localMerge.localPolicyDetail,
        decision: "deny",
        errorCode: "local_policy_denied",
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: "local_policy_denied",
        auditRecordId,
        chainDepth: chainResult.chainDepth,
        localPolicyApplied: true,
      });
    }

    const statefulEval = await evaluateStatefulConstraints(payload.constraints, requestContext, payload, {
      idempotencyKey: requestIdempotencyKey(req, requestContext),
    });

    if (!statefulEval.pass) {
      const auditRecordId = await createAuditRecord({
        credentialId: payload.credentialId,
        agentId: payload.agentId,
        issuerId: payload.issuerId,
        trustTier: payload.trustTier,
        action: requestedAction,
        resource: requestContext.resource,
        requestContext,
        delegationDepth: chainResult.chainDepth,
        constraintResults: [...constraintEval.results, ...statefulEval.results],
        localPolicyApplied: localMerge.localPolicyApplied,
        localPolicyDetail: localMerge.localPolicyDetail,
        decision: "deny",
        errorCode: statefulEval.error,
        httpStatus: 200,
      });

      return res.status(200).json({
        decision: "deny",
        error: statefulEval.error,
        auditRecordId,
        chainDepth: chainResult.chainDepth,
        constraintResults: constraintEval.results,
        statefulResults: statefulEval.results,
      });
    }

    // Allow
    const auditRecordId = await createAuditRecord({
      credentialId: payload.credentialId,
      agentId: payload.agentId,
      issuerId: payload.issuerId,
      trustTier: payload.trustTier,
      action: requestedAction,
      resource: requestContext.resource,
      requestContext,
      delegationDepth: chainResult.chainDepth,
      constraintResults: [...constraintEval.results, ...statefulEval.results],
      localPolicyApplied: localMerge.localPolicyApplied,
      decision: "allow",
      httpStatus: 200,
    });

    return res.status(200).json({
      decision: "allow",
      auditRecordId,
      chainDepth: chainResult.chainDepth,
      constraintResults: constraintEval.results,
      statefulResults: statefulEval.results,
      localPolicyApplied: localMerge.localPolicyApplied,
    });
  } catch (err) {
    console.error("Batch evaluation error:", err);
    if (err && typeof err.message === "string" && err.message.startsWith("audit_signing_failed")) {
      return res.status(500).json({ error: "audit_signing_failed", message: err.message });
    }
    return res.status(500).json({ error: "internal_error", message: "Batch evaluation failed" });
  }
});

// ── POST /evaluate/workflow ─────────────────────────────────────────
// Multi-principal workflow composition (Plan 7).
router.post("/workflow", async (req, res) => {
  const { workflowPolicyId, credentials, requestContext } = req.body || {};

  if (!workflowPolicyId) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: workflowPolicyId" });
  }
  if (!Array.isArray(credentials) || credentials.length === 0) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: credentials (non-empty array)" });
  }
  if (!requestContext || !requestContext.action || !requestContext.resource) {
    return res.status(400).json({ error: "validation_error", message: "Missing required field: requestContext with action and resource" });
  }

  let policy;
  try {
    const pool = getPool();
    const { rows } = await pool.query(
      `SELECT id, version, combinator, threshold_n, required_roles, active
       FROM portauth_workflow_policies
       WHERE id = $1 AND active = TRUE`,
      [workflowPolicyId],
    );
    if (rows.length === 0) {
      return res.status(404).json({ error: "workflow_policy_unknown", message: `No active policy with id ${workflowPolicyId}` });
    }
    policy = rows[0];
  } catch (err) {
    return res.status(500).json({ error: "internal_error", message: `Failed to load workflow policy: ${err.message}` });
  }

  const presentedRoles = credentials.map((c) => c.role);
  const coverage = validateRoleCoverage(policy, presentedRoles);
  if (!coverage.ok) {
    return res.status(200).json({
      decision: "deny",
      error: coverage.errorCode,
      message: coverage.detail,
      workflowPolicyId,
    });
  }

  // Evaluate each credential by reusing the single-credential pipeline logic.
  // To keep this endpoint self-contained, we call the helper directly here
  // using the same module-level imports.
  const { verifyCredential } = await import("../services/credentialVerifier.js");
  const subDecisions = [];

  for (const entry of credentials) {
    if (!entry.credential || !entry.presenterId || !entry.role) {
      subDecisions.push({ role: entry.role || null, decision: "deny", error: "validation_error", message: "credential, presenterId, role are required" });
      continue;
    }
    const verification = await verifyCredential(entry.credential, entry.presenterId, {
      evaluatorId: evaluatorId(),
      requestContext,
      proofOfPossession: entry.proofOfPossession,
    });
    if (!verification.verified) {
      subDecisions.push({ role: entry.role, presenterId: entry.presenterId, decision: "deny", error: verification.errorCode, message: verification.error });
      continue;
    }
    const payload = verification.payload;
    const enriched = enrichRequestContext({ requestContext, payload, presenterId: entry.presenterId, req });

    // Require the role's declared permission to be satisfied
    const declaredPermission = (policy.required_roles.find((r) => r.role === entry.role) || {}).permission;
    if (declaredPermission && !payload.permissions.includes(declaredPermission)) {
      subDecisions.push({ role: entry.role, presenterId: entry.presenterId, decision: "deny", error: "permission_denied", message: `Role ${entry.role} requires permission ${declaredPermission}` });
      continue;
    }

    // Constraint evaluation for the requested action
    if (!payload.permissions.includes(requestContext.action)) {
      subDecisions.push({ role: entry.role, presenterId: entry.presenterId, decision: "deny", error: "permission_denied", message: `Role ${entry.role} cannot perform ${requestContext.action}` });
      continue;
    }
    const ce = await evaluateConstraints(payload.constraints, enriched);
    if (!ce.pass) {
      subDecisions.push({ role: entry.role, presenterId: entry.presenterId, decision: "deny", error: ce.error });
      continue;
    }

    const subAuditId = await createAuditRecord({
      credentialId: payload.credentialId,
      agentId: payload.agentId,
      issuerId: payload.issuerId,
      trustTier: payload.trustTier,
      action: requestContext.action,
      resource: requestContext.resource,
      requestContext: enriched,
      verificationResult: { valid: true, checks: verification.checks },
      permissionMatch: { matched: true },
      constraintResults: ce.results,
      decision: "allow",
      httpStatus: 200,
    });
    subDecisions.push({ role: entry.role, presenterId: entry.presenterId, decision: "allow", auditRecordId: subAuditId });
  }

  const combined = combineSubDecisions(policy, subDecisions);

  const wrappingAuditId = await createAuditRecord({
    action: requestContext.action,
    resource: requestContext.resource,
    requestContext,
    decision: combined.decision,
    errorCode: combined.decision === "deny" ? "workflow_denied" : null,
    httpStatus: 200,
    workflowPolicyId: policy.id,
    workflowSubAuditIds: subDecisions.map((d) => d.auditRecordId).filter(Boolean),
  });

  return res.status(200).json({
    decision: combined.decision,
    reason: combined.reason,
    workflowPolicyId: policy.id,
    subDecisions,
    auditRecordId: wrappingAuditId,
  });
});

export default router;
